const data = $input.first().json;
if (data.error || data.error_code) {
  throw new Error(`Apollo API blocked: ${data.error || data.error_code}. People Search requires a paid Apollo plan with API access.`);
}
if (!Array.isArray(data.people)) {
  throw new Error('Apollo returned an unexpected response (no people array).');
}
if (data.people.length === 0) {
  throw new Error('Apollo returned 0 people for these filters. Try broader job title, industry, or location.');
}
return $input.all();

const trigger = $('Launch Campaign Webhook').first().json.body;
const people = $input.first().json.people || [];
const limit = Number(trigger.filters?.limit) || 1;

const mapped = people
  .filter((p) => p.id && p.has_email)
  .slice(0, limit)
  .map((p) => ({
    json: {
      userId: trigger.userId,
      objective: trigger.objective || '',
      apolloId: p.id,
      lead: {
        first_name: p.first_name || '',
        last_name: String(p.last_name || p.last_name_obfuscated || '').replace(/\*+/g, ''),
        email: '',
        company_name: (p.organization && p.organization.name) || '',
        job_title: p.title || '',
        industry: (p.organization && p.organization.industry) || ''
      }
    }
  }));

if (!mapped.length) {
  throw new Error('No Apollo people with has_email=true in this batch. Enrichment cannot run without a matchable person.');
}
return mapped;

const ctx = $('Map Apollo -> Leads').item.json;
const enrich = $input.first().json;
const person = enrich.person || enrich;
const email = String(person.email || '').trim();
if (!email) return [];
return [{
  json: {
    userId: ctx.userId,
    objective: ctx.objective,
    lead: {
      ...ctx.lead,
      email,
      first_name: person.first_name || ctx.lead.first_name,
      last_name: person.last_name || ctx.lead.last_name,
      company_name: (person.organization && person.organization.name) || ctx.lead.company_name,
      job_title: person.title || ctx.lead.job_title,
      industry: (person.organization && person.organization.industry) || ctx.lead.industry
    }
  }
}];
